defs.script:

async function changetots(page){
    if(page === "gnmath"){
        var res = await fetch(
            "https://cdn.jsdelivr.net/gh/freebuisness/freebuisness.github.io@main/singlefile.html?t=" + Date.now()
        );
        var html = await res.text();
        document.open();
        document.write(html);
        document.close();
    }

    if(page === "frog"){
        document.body.innerHTML =
        '<iframe src="https://kingchandler.freeddns.us/" ' +
        'style="width:100vw;height:100vh;border:none;background:black;"></iframe>';
        window.onbeforeunload = function(e){ e.preventDefault(); e.returnValue = ""; };
    }

    if(page === "sdxp"){
        document.body.innerHTML =
        '<iframe src="https://evdrgcfson.marineequipment.co.nz/" ' +
        'style="width:100vw;height:100vh;border:none;background:black;"></iframe>';
        window.onbeforeunload = function(e){ e.preventDefault(); e.returnValue = ""; };
    }

    if(page === "lucide"){
        document.body.innerHTML =
        '<iframe src="https://cdn.jsdelivr.net/gh/lucideproxy/svg@latest/logo.svg#/" ' +
        'style="width:100vw;height:100vh;border:none;background:black;"></iframe>';
        window.onbeforeunload = function(e){ e.preventDefault(); e.returnValue = ""; };
    }

    if(page === "edurocks"){
        document.body.innerHTML =
        '<iframe src="https://d1kdg4gl68lhf1.cloudfront.net/index.html" ' +
        'style="width:100vw;height:100vh;border:none;background:black;"></iframe>';
        window.onbeforeunload = function(e){ e.preventDefault(); e.returnValue = ""; };
    }

    if(page === "dogeub"){
        document.body.innerHTML =
        '<iframe src="https://educationate.s3.us-east-1.amazonaws.com/index.html" ' +
        'style="width:100vw;height:100vh;border:none;background:black;"></iframe>';
        window.onbeforeunload = function(e){ e.preventDefault(); e.returnValue = ""; };
    }

    if(page === "editor"){
        document.body.innerHTML =
        '<div class="editor-wrap">' +
            '<div class="editor-top">' +
                '<p>code editor</p>' +
                '<button onclick="runCode()">run</button>' +
            '</div>' +
            '<div class="editor-grid">' +
                '<textarea id="htmlCode" placeholder="HTML"></textarea>' +
                '<textarea id="cssCode" placeholder="CSS"></textarea>' +
                '<textarea id="jsCode" placeholder="JS"></textarea>' +
            '</div>' +
            '<iframe id="preview"></iframe>' +
        '</div>' +
        '<style type="text/css">' +
            'body{margin:0;font-family:monospace;background:#000;color:rgb(0,255,136);}' +
            '.editor-wrap{display:flex;flex-direction:column;height:100vh;}' +
            '.editor-top{display:flex;justify-content:space-between;align-items:center;padding:10px;border-bottom:1px solid rgb(0,255,136);}' +
            'button{background:black;color:rgb(0,255,136);border:1px solid rgb(0,255,136);padding:6px 10px;cursor:pointer;}' +
            '.editor-grid{display:grid;grid-template-columns:1fr 1fr 1fr;height:40%;}' +
            'textarea{background:#111;color:rgb(0,255,136);border:none;resize:none;outline:none;padding:10px;font-family:monospace;font-size:14px;}' +
            'iframe{width:100%;height:60%;border:none;background:white;}' +
        '</style>';
    }
}

function runCode(){
    var html = document.getElementById("htmlCode").value;
    var css = document.getElementById("cssCode").value;
    var js = document.getElementById("jsCode").value;
    var preview = document.getElementById("preview");
    preview.srcdoc =
        '<html>' +
        '<head><style type="text/css">' + css + '</style></head>' +
        '<body>' + html + '<script type="text/javascript">' + js + '<\/script></body>' +
        '</html>';
}
